import { useNavigate } from "react-router-dom";
import React, { useState, useRef, useEffect, useCallback, memo } from "react";
import paper from "paper";
import "../styles/auth/login.css";

const LoginForm = memo(({ onSubmit }) => {
  const [loginEmail, setLoginEmail] = useState("");
  const [loginPassword, setLoginPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);

  const handleSubmit = useCallback(
    (e) => {
      e.preventDefault();
      onSubmit({ loginUsername: loginEmail, loginPassword });
    },
    [loginEmail, loginPassword, onSubmit]
  );

  const togglePassword = useCallback(() => {
    setShowPassword((prev) => !prev);
  }, []);

  return (
    <div className="login-card">
      <div className="login-header">
        <div className="logo">
          <svg width="48" height="48" viewBox="0 0 48 48" fill="none">
            <rect width="48" height="48" rx="8" fill="#0070FF" />
            <text
              x="24"
              y="32"
              textAnchor="middle"
              fill="white"
              fontSize="20"
              fontWeight="700"
              fontFamily="Arial, sans-serif"
            >
              V2X
            </text>
          </svg>
        </div>
        <h1>Prism Dashboard</h1>
        <p>Welcome! Please sign in to continue</p>
      </div>

      <form
        className="login-form"
        id="loginForm"
        noValidate
        onSubmit={handleSubmit}
      >
        <div className="input-group">
          <input
            type="email"
            id="email"
            name="email"
            required
            autoComplete="email"
            placeholder=" "
            value={loginEmail}
            onChange={(e) => setLoginEmail(e.target.value)}
          />
          <label htmlFor="email">Email address</label>
          <span className="input-border"></span>
          <span className="error-message" id="emailError"></span>
        </div>

        <div className="input-group">
          <input
            type={showPassword ? "text" : "password"}
            id="password"
            name="password"
            required
            autoComplete="current-password"
            placeholder=" "
            value={loginPassword}
            onChange={(e) => setLoginPassword(e.target.value)}
          />
          <label htmlFor="password">Password</label>
          <button
            type="button"
            className="password-toggle"
            id="passwordToggle"
            aria-label="Toggle password visibility"
            onClick={togglePassword}
          >
            <svg
              className="eye-icon"
              width="16"
              height="16"
              viewBox="0 0 16 16"
              fill="none"
            >
              <path
                d="M8 3C4.5 3 1.6 5.6 1 8c.6 2.4 3.5 5 7 5s6.4-2.6 7-5c-.6-2.4-3.5-5-7-5zm0 8.5A3.5 3.5 0 118 4.5a3.5 3.5 0 010 7zm0-5.5a2 2 0 100 4 2 2 0 000-4z"
                fill="currentColor"
              />
            </svg>
          </button>
          <span className="input-border"></span>
          <span className="error-message" id="passwordError"></span>
        </div>

        <div className="form-options">
          <label className="checkbox-container">
            <input
              type="checkbox"
              id="remember"
              name="remember"
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
            />
            <span className="checkmark">
              <svg width="10" height="8" viewBox="0 0 10 8" fill="none">
                <path
                  d="M1 4l2.5 2.5L9 1"
                  stroke="currentColor"
                  strokeWidth="1.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            </span>
            Remember me
          </label>
          <a href="#" className="forgot-link">
            Forgot password?
          </a>
        </div>

        <button type="submit" className="submit-btn">
          <span className="btn-text">Sign in</span>
          <div className="btn-loader">
            <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
              <circle
                cx="9"
                cy="9"
                r="7"
                stroke="currentColor"
                strokeWidth="2"
                opacity="0.25"
              />
              <path
                d="M16 9a7 7 0 01-7 7"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
              >
                <animateTransform
                  attributeName="transform"
                  type="rotate"
                  dur="1s"
                  values="0 9 9;360 9 9"
                  repeatCount="indefinite"
                />
              </path>
            </svg>
          </div>
        </button>
      </form>
    </div>
  );
});

